void analyze(int* arr, int n, int* sum, int* max, int* min)
{
	for (int i = 0; i < n; i++)
	{
		if (i == 0)
		{
			*max = arr[i];
			*min = arr[i];
		}
		else
		{
			if (*max < arr[i])
				*max = arr[i];

			if (*min > arr[i])
				*min = arr[i];
		}
		*sum += arr[i];
	}
}

int partial_sum(int* arr, int n, int start)
{
	int sum = 0;

	for (int i = start; i < n; i++)
	{
		sum += arr[i];
	}
	return sum;
