			index = i;
		}
		else
		{
			if (arr[i] > max)
			{
				max = arr[i];
				index = i;
			}
		}
	}
	return index;
}
void remove_duplicate(int* arr, int n)
{
	int zero_index = n - 1;

	for (int i = 0; i < n; i++)
	{
		for (int j = i + 1; j <= zero_index; j++)
		{
			if (arr[i] == arr[j])
			{
				for (int k = j; k < zero_index; k++)
				{
					arr[k] = arr[k + 1];
				}
				arr[zero_index] = 0;
				zero_index--;
				j--;
			}
		}
	}

