		//첫번째 행을 받아온 값을 바로계산해서 바로 fprintf로 total_score.csv에 뿌려줌
		sum = stu[idx].kor + stu[idx].eng + stu[idx].math;
		average = sum / 3.0;
		fprintf(f2, "%s, %d, %d, %d, %d, %0.2f", stu[idx].name, stu[idx].kor, stu[idx].eng, stu[idx].math, sum, average);
		idx++;
	}

	fclose(f);
	fclose(f2);

	return 0;
}
